import React from "react";

export default function Forecast() {
  const dailyForecast = [
    { day: "Monday", condition: "☀️ Sunny", high: "35°C", low: "22°C" },
    { day: "Tuesday", condition: "🌧 Rainy", high: "28°C", low: "20°C" },
    { day: "Wednesday", condition: "⛅ Partly Cloudy", high: "30°C", low: "21°C" },
    { day: "Thursday", condition: "🌩 Stormy", high: "26°C", low: "18°C" },
    { day: "Friday", condition: "☀️ Sunny", high: "34°C", low: "23°C" },
  ];

  return (
    <div className="min-h-screen pt-16 px-4 pb-24 bg-black text-white">
      <h1 className="text-3xl font-bold text-center mb-6">5-Day Forecast</h1>
      <div className="space-y-4">
        {dailyForecast.map((forecast, index) => (
          <div
            key={index}
            className="flex items-center justify-between bg-white/5 backdrop-blur-md rounded-xl px-6 py-4 shadow-inner ring-1 ring-white/10"
          >
            <div>
              <p className="text-lg font-medium">{forecast.day}</p>
              <p className="text-sm text-white/60">{forecast.condition}</p>
            </div>
            <div className="text-right">
              <p className="text-lg font-bold">{forecast.high}</p>
              <p className="text-sm text-white/60">Low: {forecast.low}</p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
